import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:7000/api',
});

// 🔥 Attach token automatically
API.interceptors.request.use((req) => {
  const token = localStorage.getItem('token');

  if (token) {
    req.headers.Authorization = token;
  }

  return req;
});

// Handle 401 globally
api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }
    return Promise.reject(err);
  }
);

// ─── AUTH 
// POST /api/auth/signup
export const signup = (data) => api.post('/auth/signup', data);
// POST /api/auth/login
export const login = (data) => api.post('/auth/login', data);

// ─── PROJECTS 
// GET  /api/projects          — all projects user belongs to
export const getProjects = () => api.get('/projects');
// POST /api/projects          — Admin only
export const createProject = (data) => api.post('/projects', data);
// POST /api/projects/:id/add-member  — Admin only
export const addMember = (projectId, userId) =>
  api.post(`/projects/${projectId}/add-member`, { userId });

// ─── TASKS 
// GET  /api/tasks/:projectId
export const getTasksByProject = (projectId) => api.get(`/tasks/${projectId}`);
// POST /api/tasks
export const createTask = (data) => api.post('/tasks', data);
// PUT  /api/tasks/:id
export const updateTask = (id, data) => api.put(`/tasks/${id}`, data);

// ─── DASHBOARD 
// GET  /api/dashboard
export const getDashboard = () => api.get('/dashboard');

export default api;
